//Background
World.frameRate = 30;
var player;

var firedelay = 0;

var enemytimer = 0;

var enemy_color = ("red");

var score = 0;

var gamestate = "running";

var timespeed = 0;

var enemies = [];

var enemies_bullets =[];

var bullets = [];

var instructions = false;

var color = ("purple");

var stars = [];

for(var i = 0; i < 100; i++){
  stars.push({
    x: randomNumber(0, 390),
    y: randomNumber(0, 390),
    speed: randomNumber(1, 3)
  });
}

//Ship Sprite
player = createSprite(200,360,40,40);
player.setAnimation("ship");
player.scale = 0.25;
player.setCollider("circle", 0, 0, 100);
player.debug = true;

//Main loop
function draw(){

  background("black");

  fill("white");
  //Background
  for(var i = 0; i < stars.length; i++){
    ellipse(stars[i].x, stars[i].y, 4,4);
    stars[i].y += stars[i].speed;

    if(stars[i].y > 400){
      stars[i].y = 0;
      stars[i].x = randomNumber(0, 390);
    }
  }
  if(instructions === false){
    gamestate = "nr";
  }
  if(gamestate === "nr"){
    show_instructions();
  }

  if(gamestate === "running"){
    timespeed += 0.001;

    textSize(20);
    text("Score: " + score, 15, 40);

    //Functions
    updates();
    updatebullets();
    enemyspawning();
    updateenemies();
    bullet_hit();
    updatebullet();

    if (keyDown("space")){
      firedelay ++;
      if(firedelay >= 10){
        shootBullet();
        firedelay = 0;
      }
    } else {
      firedelay = 10;
    }
  }

  drawSprites();

  if(gamestate === "over"){
    background("black");
    fill("red");
    textSize(50);
    textAlign(CENTER);
    text("GAME OVER", 200, 200);
    textSize(20); 
    text("PRESS 'R' TO TRY AGAIN", 200, 300);
    textSize(10); 
    if(keyDown("r")){
      score = 0;
      gamereset();
      gamestate = "running";

    }
  }
} 
function show_instructions(){
    background("white");
    fill("black");
    textSize(50);
    textAlign(CENTER);
    text("INSTRUCTIONS", 200, 200);
    textSize(20); 
    text("PRESS 'SPACE' TO SHOOT", 200, 250);
    fill("blue");
    textSize(12);
    text("WASD/ARROW KEYS TO MOVE. PRESS SPACE AGAIN TO CONTINUE", 200, 300);
    if(keyWentDown("space")){
      instructions = true;
      gamestate = "running";
    }
}
//Movement/Shooting
function updates(){
  //wasd
  if(keyDown("a")){
    player.x = player.x - 5;
  }
  if(keyDown("d")){
    player.x = player.x + 5;
  }
  if(keyDown("w")){
    player.y = player.y - 5;
  }
  if(keyDown("s")){
    player.y = player.y + 5;
  }
  //Arrow Keys
   if(keyDown("LEFT_ARROW")){
    player.x = player.x - 5;
  }
  if(keyDown("RIGHT_ARROW")){
    player.x = player.x + 5;
  }
  if(keyDown("UP_ARROW")){
    player.y = player.y - 5;
  }
  if(keyDown("DOWN_ARROW")){
    player.y = player.y + 5;
  }

  player.x = constrain(player.x, 20, 390);
  player.y = constrain(player.y, 20, 390);
}
//shooting bullets
function shootBullet(){
  var bullet = createSprite(player.x + 4, player.y - 40, 7, 20);
  bullet.shapeColor = color;
  bullet.velocityY = -6;
  bullets.push(bullet);
}
//bullet upets
function updatebullets(){
  for (var i = bullets.length - 1; i >= 0; i--){
     if (bullets[i].y < 0 ){
      bullets[i].destroy();
      bullets.splice(i,1);
    }
  }
}

//Enemy Removal
function updateenemies(){
  for(var i = enemies.length - 1; i >= 0; i--){

    enemies[i].tint = null;

    if(randomNumber(1, 45) === 1){
      spawnenemybullet(enemies[i].x, enemies[i].y);
    }

    if(enemies[i].isTouching(player)){
      gamestate = "over";
    }

    if(enemies[i].y > 400){
      enemies[i].destroy();
      enemies.splice(i, 1);
    }
  }
}
//Enemy Bullet Removal
function updatebullet(){
  for(var i = enemies_bullets.length - 1; i >= 0; i--){
    if(enemies_bullets[i].isTouching(player)){
      gamestate = "over";
    }

    if(enemies_bullets[i].y > 400){
      enemies_bullets[i].destroy();
      enemies_bullets.splice(i, 1);
    }

  }

}


//Enemy bullets
function spawnenemybullet(x, y){
  var enemybullet = createSprite(x, y + 20, 5, 10);
  enemybullet.shapeColor = enemy_color;
  enemybullet.velocityY = 7 + timespeed;
  enemies_bullets.push(enemybullet);
}

//Spawning enemy
function spawnenemy(){
  var enemy = createSprite(randomNumber(20,380), -20,30,30);
  enemy.setAnimation("enemy");
  enemy.setCollider("circle", 0, 0, 60);
  enemy.scale = 0.2;
  enemy.velocityY = 2;
  enemy.hp = 3;
  enemies.push(enemy);
  enemy.debug = true;
}

//Spawn Timer
function enemyspawning(){
  enemytimer ++;

  if(enemytimer > 50){
    spawnenemy();   
    enemytimer = 0;
  }
}

//Game reset
function gamereset(){
  for (var i = 0; i < enemies.length; i++){
    enemies[i].destroy();
  }
   enemies = [];

   for (var k = 0; k < enemies_bullets.length; k++) {
      enemies_bullets[k].destroy();
  }

    enemies_bullets = [];

   for(var j = 0; j < bullets.length; j++){
     bullets[j].destroy();
   }
   bullets = [];
   player.x = 200;
   player.y = 360;

}

//bullet hits
function bullet_hit(){
  for(var j = bullets.length - 1; j >= 0; j--){
    for(var i = enemies.length -1; i >=0; i--){
      if(bullets[j] && enemies[i] && bullets[j].isTouching(enemies[i])){

        enemies[i].tint = ("red");
        bullets[j].destroy();
        bullets.splice(j, 1);

        enemies[i].hp = enemies[i].hp - 1;

        if(enemies[i].hp <= 0){
          score = score + 1;
          enemies[i].destroy();
          enemies.splice(i, 1);
        }

        break;

      }
    }
  }
}
